sql:
SELECT message, priority
FROM secure_messages
WHERE status = 'unread';

SELECT resource_name
FROM educational_resources
WHERE patient_id = 1;

SELECT resource_name, ratings
FROM educational_resources
ORDER BY ratings DESC;

SELECT COUNT(*) AS total_resources
FROM educational_resources
WHERE language = 'Spanish';

SELECT COUNT(DISTINCT patient_id) AS total_patients_with_active_treatments
FROM treatment_plans
WHERE status = 'active';

SELECT username, notification_preferences
FROM patient_portal
WHERE patient_id = 1;

